//go:build vectors

package server

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/search"

	"github.com/modelcontextprotocol/go-sdk/mcp"
)

// registerTools registers all 4 MCP tools.
func (s *Server) registerTools() {
	// search tool
	type SearchArgs struct {
		Query string   `json:"query" jsonschema:"description=What you're looking for. Natural language works best."`
		Scope string   `json:"scope,omitempty" jsonschema:"enum=global,enum=project,enum=all,description=Filter by knowledge scope."`
		Kind  string   `json:"kind,omitempty" jsonschema:"enum=reference,enum=decision,enum=trace,description=Filter by document type."`
		Tags  []string `json:"tags,omitempty" jsonschema:"description=Filter to documents tagged with ALL of these tags."`
		Limit int      `json:"limit,omitempty" jsonschema:"description=Maximum number of results (default 5, max 20)."`
	}

	mcp.AddTool(s.mcp, &mcp.Tool{
		Name:        "search",
		Description: "Search the knowledge base for relevant sections. Returns ranked results with titles, snippets, and scores. Use this to find knowledge about a topic.",
	}, func(ctx context.Context, req *mcp.CallToolRequest, args SearchArgs) (*mcp.CallToolResult, any, error) {
		query := strings.TrimSpace(args.Query)
		if query == "" {
			return errorResult("invalid_parameter: query is required and must be non-empty"), nil, nil
		}

		scope := args.Scope
		if scope != "" && scope != "global" && scope != "project" && scope != "all" {
			return errorResult("invalid_parameter: scope must be one of: global, project, all"), nil, nil
		}

		kind := args.Kind
		if kind != "" && kind != "reference" && kind != "decision" && kind != "trace" {
			return errorResult("invalid_parameter: kind must be one of: reference, decision, trace"), nil, nil
		}

		limit := args.Limit
		if limit <= 0 {
			limit = 5
		}
		if limit > 20 {
			limit = 20
		}

		resp, err := s.searcher.Search(ctx, query, scope, kind, args.Tags, limit)
		if err != nil {
			return errorResult(fmt.Sprintf("internal: %v", err)), nil, nil
		}

		text := formatSearchText(resp)

		// Build structured content
		structured := map[string]any{
			"type":    "searchResponse",
			"results": formatSearchResults(resp.Results),
			"meta": map[string]any{
				"totalMatches": resp.TotalMatches,
				"searchTimeMs": resp.SearchTimeMs,
				"indexState":   resp.IndexState,
				"query":        query,
			},
		}

		if resp.BM25Only {
			structured["meta"].(map[string]any)["hint"] = "bm25_only_fallback"
		}

		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: text},
			},
		}, structured, nil
	})

	// read tool
	type ReadArgs struct {
		ID      string `json:"id" jsonschema:"description=Qualified section ID (document:section) or document slug."`
		Context int    `json:"context,omitempty" jsonschema:"description=Number of surrounding sections to include."`
	}

	mcp.AddTool(s.mcp, &mcp.Tool{
		Name:        "read",
		Description: "Retrieve full content of a knowledge section by its ID, or get a table of contents for a document. Use section IDs from search results.",
	}, func(ctx context.Context, req *mcp.CallToolRequest, args ReadArgs) (*mcp.CallToolResult, any, error) {
		id := strings.TrimSpace(args.ID)
		if id == "" {
			return errorResult("invalid_parameter: id is required and must be non-empty"), nil, nil
		}

		contextN := args.Context
		if contextN < 0 {
			contextN = 0
		}
		if contextN > 5 {
			contextN = 5
		}

		resp, err := s.searcher.Read(id, contextN)
		if err != nil {
			return errorResult(fmt.Sprintf("internal: %v", err)), nil, nil
		}

		if !resp.Found && resp.Error != nil {
			if resp.Error.Code == "ambiguous_id" {
				return errorResult(fmt.Sprintf("ambiguous_id: %s", resp.Error.Message)), nil, nil
			}
			return errorResult(fmt.Sprintf("not_found: %s", resp.Error.Message)), nil, nil
		}

		text := formatReadText(resp)

		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: text},
			},
		}, resp, nil
	})

	// index tool
	type IndexArgs struct {
		Path  string `json:"path" jsonschema:"description=Absolute path to a markdown file or directory."`
		Scope string `json:"scope,omitempty" jsonschema:"enum=global,enum=project,description=Knowledge scope (default: project)."`
		Kind  string `json:"kind,omitempty" jsonschema:"enum=reference,enum=decision,enum=trace,description=Document type (default: reference)."`
		Force bool   `json:"force,omitempty" jsonschema:"description=Force full rebuild ignoring hashes."`
	}

	mcp.AddTool(s.mcp, &mcp.Tool{
		Name:        "index",
		Description: "Index a markdown file or directory into the knowledge base. Uses hash-based incrementalism: unchanged files are skipped. Use force=true to rebuild.",
	}, func(ctx context.Context, req *mcp.CallToolRequest, args IndexArgs) (*mcp.CallToolResult, any, error) {
		path := strings.TrimSpace(args.Path)
		if path == "" {
			return errorResult("invalid_parameter: path is required and must be non-empty"), nil, nil
		}

		scope := args.Scope
		if scope == "" {
			scope = "project"
		}
		if scope != "global" && scope != "project" {
			return errorResult("invalid_parameter: scope must be one of: global, project"), nil, nil
		}

		kind := args.Kind
		if kind == "" {
			kind = "reference"
		}
		if kind != "reference" && kind != "decision" && kind != "trace" {
			return errorResult("invalid_parameter: kind must be one of: reference, decision, trace"), nil, nil
		}

		result, err := s.pipeline.IndexPath(ctx, path, scope, kind, args.Force)
		if err != nil {
			return errorResult(fmt.Sprintf("index_error: %v", err)), nil, nil
		}

		text := formatIndexText(result)

		structured := map[string]any{
			"type": "indexResponse",
			"result": map[string]any{
				"indexed":    result.Indexed,
				"unchanged":  result.Unchanged,
				"removed":    result.Removed,
				"errors":     result.Errors,
				"chunks":     result.Chunks,
				"durationMs": result.Duration.Milliseconds(),
			},
			"details": result.Details,
			"errors":  result.FileErrors,
		}

		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: text},
			},
		}, structured, nil
	})

	// status tool
	type StatusArgs struct{}

	mcp.AddTool(s.mcp, &mcp.Tool{
		Name:        "status",
		Description: "Check server health, index statistics, and embedder status. No parameters needed.",
	}, func(ctx context.Context, req *mcp.CallToolRequest, args StatusArgs) (*mcp.CallToolResult, any, error) {
		indexer := s.pipeline.Indexer()
		docCount := indexer.DocCount()
		chunkCount := indexer.ChunkCount()

		indexState := "empty"
		if chunkCount > 0 {
			indexState = "ready"
		}

		// Check embedder health (quick test)
		embedderStatus := "healthy"
		if s.embedder != nil {
			testCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
			defer cancel()
			_, err := s.embedder.Embed(testCtx, "health", 1) // PurposeQuery
			if err != nil {
				embedderStatus = "unreachable"
			}
		}

		uptime := s.Uptime()
		ready := embedderStatus == "healthy"

		text := formatStatusText(ready, docCount, chunkCount, indexState,
			s.cfg.Embedder.Backend, s.cfg.Embedder.Model, s.cfg.Embedder.Dimensions,
			embedderStatus, uptime)

		structured := map[string]any{
			"type":   "statusResponse",
			"ready":  ready,
			"uptime": uptime.Round(time.Second).String(),
			"index": map[string]any{
				"state":         indexState,
				"documentCount": docCount,
				"chunkCount":    chunkCount,
			},
			"embedder": map[string]any{
				"backend":    s.cfg.Embedder.Backend,
				"model":      s.cfg.Embedder.Model,
				"dimensions": s.cfg.Embedder.Dimensions,
				"status":     embedderStatus,
			},
		}

		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: text},
			},
		}, structured, nil
	})
}

// errorResult creates an IsError=true result.
func errorResult(msg string) *mcp.CallToolResult {
	return &mcp.CallToolResult{
		Content: []mcp.Content{
			&mcp.TextContent{Text: "Error: " + msg},
		},
		IsError: true,
	}
}

// formatSearchText formats search results as LLM-readable text.
func formatSearchText(resp search.SearchResponse) string {
	if resp.IndexState == "empty" {
		return "No results. The knowledge index is empty — use the 'index' tool to add documents first."
	}

	if len(resp.Results) == 0 {
		return fmt.Sprintf("No results (0 matches). Try broader terms or different filters.")
	}

	var b strings.Builder
	bm25Note := ""
	if resp.BM25Only {
		bm25Note = " (Note: semantic search unavailable — results based on keyword matching only)"
	}

	fmt.Fprintf(&b, "Found %d results (%d total matches, %dms):%s\n",
		len(resp.Results), resp.TotalMatches, resp.SearchTimeMs, bm25Note)

	for i, r := range resp.Results {
		score := search.RoundScore(r.Score)
		fmt.Fprintf(&b, "\n[%d] %s (%s) [score: %.4f]\n", i+1, r.Title, r.QualifiedID, score)
		fmt.Fprintf(&b, "    Source: %s | Scope: %s | Kind: %s", r.DocumentSlug, r.Scope, r.Kind)
		if len(r.Tags) > 0 {
			fmt.Fprintf(&b, " | Tags: %s", strings.Join(r.Tags, ", "))
		}
		fmt.Fprintf(&b, "\n    %s\n", r.Snippet)
	}

	return b.String()
}

// formatReadText formats a read response as LLM-readable text.
func formatReadText(resp search.ReadResponse) string {
	if !resp.Found {
		return "Not found."
	}

	if resp.Mode == "toc" && resp.Document != nil {
		return formatReadTOCText(resp)
	}

	return formatReadSectionText(resp)
}

func formatReadSectionText(resp search.ReadResponse) string {
	if resp.Section == nil {
		return "Not found."
	}

	var b strings.Builder
	s := resp.Section

	if len(resp.Context) > 0 {
		// Find context before the primary section
		for _, c := range resp.Context {
			if c.Position < s.Position {
				fmt.Fprintf(&b, "--- Context: before ---\n\n")
				fmt.Fprintf(&b, "## %s\n\n", c.Title)
				fmt.Fprintf(&b, "Source: %s | Scope: %s | Kind: %s\n\n", c.DocumentSlug, c.Scope, c.Kind)
				fmt.Fprintf(&b, "%s\n\n", c.Content)
			}
		}
	}

	if len(resp.Context) > 0 {
		fmt.Fprintf(&b, "--- Primary section ---\n\n")
	}

	fmt.Fprintf(&b, "## %s\n\n", s.Title)
	fmt.Fprintf(&b, "Source: %s | Scope: %s | Kind: %s\n\n", s.DocumentSlug, s.Scope, s.Kind)
	fmt.Fprintf(&b, "%s\n", s.Content)

	if len(resp.Context) > 0 {
		for _, c := range resp.Context {
			if c.Position > s.Position {
				fmt.Fprintf(&b, "\n--- Context: after ---\n\n")
				fmt.Fprintf(&b, "## %s\n\n", c.Title)
				fmt.Fprintf(&b, "Source: %s | Scope: %s | Kind: %s\n\n", c.DocumentSlug, c.Scope, c.Kind)
				fmt.Fprintf(&b, "%s\n", c.Content)
			}
		}
	}

	return b.String()
}

func formatReadTOCText(resp search.ReadResponse) string {
	if resp.Document == nil {
		return "Not found."
	}

	var b strings.Builder
	d := resp.Document

	fmt.Fprintf(&b, "# %s — %s\n\n", d.Slug, d.Title)
	fmt.Fprintf(&b, "Scope: %s | Kind: %s | Sections: %d\n\n", d.Scope, d.Kind, d.SectionCount)
	fmt.Fprintf(&b, "Table of contents:\n")

	for i, s := range resp.Sections {
		fmt.Fprintf(&b, "  %d. %s  %s\n", i+1, s.SectionID, s.Title)
	}

	fmt.Fprintf(&b, "\nUse read(id: \"%s:<sectionId>\") to read a specific section.\n", d.Slug)
	return b.String()
}

// formatIndexText formats an index result as LLM-readable text.
func formatIndexText(result interface{}) string {
	// Type assert to access fields
	type indexLike interface {
		getIndexed() int
		getUnchanged() int
	}

	// Use JSON round-trip for simplicity
	data, _ := json.Marshal(result)
	var m map[string]any
	json.Unmarshal(data, &m)

	indexed := getIntFromMap(m, "Indexed")
	unchanged := getIntFromMap(m, "Unchanged")
	removed := getIntFromMap(m, "Removed")
	errors := getIntFromMap(m, "Errors")
	chunks := getIntFromMap(m, "Chunks")
	durationMs := getIntFromMap(m, "Duration") / 1e6 // nanoseconds to ms

	var b strings.Builder

	if indexed == 0 && unchanged > 0 && removed == 0 {
		fmt.Fprintf(&b, "No changes detected. All %d documents unchanged (use force=true to rebuild).\n", unchanged)
		return b.String()
	}

	if indexed > 0 {
		fmt.Fprintf(&b, "Indexed %d document(s) (%d chunks) in %dms.", indexed, chunks, durationMs)
	}
	if unchanged > 0 {
		fmt.Fprintf(&b, " Skipped %d unchanged.", unchanged)
	}
	if removed > 0 {
		fmt.Fprintf(&b, " Removed %d deleted.", removed)
	}
	if errors > 0 {
		fmt.Fprintf(&b, " %d files failed.", errors)
	}
	fmt.Fprintln(&b)

	return b.String()
}

func getIntFromMap(m map[string]any, key string) int {
	if v, ok := m[key]; ok {
		switch t := v.(type) {
		case float64:
			return int(t)
		case int:
			return t
		}
	}
	return 0
}

func formatSearchResults(results []search.SearchResult) []map[string]any {
	out := make([]map[string]any, len(results))
	for i, r := range results {
		out[i] = map[string]any{
			"qualifiedId":  r.QualifiedID,
			"documentSlug": r.DocumentSlug,
			"sectionId":    r.SectionID,
			"title":        r.Title,
			"score":        search.RoundScore(r.Score),
			"snippet":      r.Snippet,
			"scope":        r.Scope,
			"kind":         r.Kind,
			"tags":         r.Tags,
		}
	}
	return out
}

// formatStatusText formats the status response as LLM-readable text.
func formatStatusText(ready bool, docCount, chunkCount int, indexState, backend, model string, dims int, embedderStatus string, uptime time.Duration) string {
	var b strings.Builder

	state := "ready"
	if !ready {
		state = "degraded"
	}
	if indexState == "empty" {
		state += " (index empty)"
	}

	fmt.Fprintf(&b, "Knowledge MCP Server: %s\n\n", state)
	fmt.Fprintf(&b, "Index: %d documents, %d chunks\n", docCount, chunkCount)

	if indexState == "empty" {
		fmt.Fprintf(&b, "  Use the 'index' tool to add markdown documents.\n")
	}

	fmt.Fprintf(&b, "\nEmbedder: %s (%s, %d-dim) — %s\n", backend, model, dims, embedderStatus)
	if embedderStatus == "unreachable" {
		fmt.Fprintf(&b, "  Search will fall back to keyword matching only.\n")
		fmt.Fprintf(&b, "  Index operations will fail until embedder is restored.\n")
	}

	fmt.Fprintf(&b, "Uptime: %s\n", uptime.Round(time.Second))
	return b.String()
}
